import { Router } from 'express';
import { authController } from './auth.controller.js';
import { authenticate } from '../../middlewares/authenticate.js';
import { authorizeRoles } from '../../middlewares/authorize.js';
import { resolveTenantFromSubdomain } from '../../middlewares/resolve-tenant-from-subdomain.js';
export const authRouter = Router();
authRouter.post('/register', resolveTenantFromSubdomain, authController.register);
authRouter.post('/login', resolveTenantFromSubdomain, authController.login);
authRouter.get('/me', authenticate, authController.me);
authRouter.get('/admin-area', authenticate, authorizeRoles('ADMIN'), authController.adminArea);
